const encoder = new TextEncoder();

function htmlEscape(value) {
  return String(value).replace(/[&<>"']/g, ch => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[ch]));
}

function parseCookies(header) {
  const cookies = {};
  String(header || '').split(';').forEach(part => {
    const index = part.indexOf('=');
    if (index === -1) return;
    cookies[part.slice(0, index).trim()] = part.slice(index + 1).trim();
  });
  return cookies;
}

function hex(buffer) {
  return Array.from(new Uint8Array(buffer)).map(byte => byte.toString(16).padStart(2, '0')).join('');
}

async function signature(payload) {
  const key = await crypto.subtle.importKey('raw', encoder.encode(SESSION_SECRET), { name: 'HMAC', hash: 'SHA-256' }, false, ['sign']);
  return hex(await crypto.subtle.sign('HMAC', key, encoder.encode(payload)));
}

function safeEqual(a, b) {
  if (a.length !== b.length) return false;
  let out = 0;
  for (let i = 0; i < a.length; i++) out |= a.charCodeAt(i) ^ b.charCodeAt(i);
  return out === 0;
}

async function makeSessionCookie(username) {
  const expires = Date.now() + 1000 * 60 * 60 * 24 * 30;
  const payload = encodeURIComponent(username) + '.' + expires;
  const sig = await signature(payload);
  return 'mealmate_session=' + payload + '.' + sig + '; Path=/; Max-Age=2592000; HttpOnly; Secure; SameSite=Lax';
}

async function currentClient(request) {
  const raw = parseCookies(request.headers.get('Cookie')).mealmate_session;
  if (!raw) return null;
  const parts = raw.split('.');
  if (parts.length !== 3) return null;
  const username = decodeURIComponent(parts[0]);
  const expires = Number(parts[1]);
  const sig = parts[2];
  if (!ACCOUNTS[username] || !expires || Date.now() > expires) return null;
  const expected = await signature(parts[0] + '.' + parts[1]);
  if (!safeEqual(sig, expected)) return null;
  return { username, name: ACCOUNTS[username].name || username };
}

function loginPage(error) {
  const message = error ? '<div class="error">الحساب أو كلمة السر غير صحيحة</div>' : '<div class="error"></div>';
  return '<!doctype html><html lang="ar" dir="rtl"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover"><title>MealMate Login</title><style>' +
    ':root{color-scheme:light}*{box-sizing:border-box}body{margin:0;min-height:100svh;display:flex;align-items:center;justify-content:center;padding:16px;background:radial-gradient(800px 360px at 20% 0%,#f8dce9 0%,transparent 58%),linear-gradient(145deg,#fdf2f7,#f7edf9 52%,#eef8f4);color:#4a2f3e;font-family:system-ui,-apple-system,Segoe UI,sans-serif}.card{width:min(420px,100%);background:white;border:1px solid #f3dde8;border-radius:18px;box-shadow:0 18px 55px rgba(120,40,90,.18);padding:22px}.mark{width:54px;height:54px;border-radius:16px;background:linear-gradient(135deg,#e07ba6,#c08bc4);display:flex;align-items:center;justify-content:center;color:white;font-size:25px;margin-bottom:14px}h1{font-size:28px;line-height:1.1;margin:0}p{margin:8px 0 18px;color:#8b6d82;font-weight:750;line-height:1.55}.field{display:grid;gap:7px;margin:12px 0}.field span{font-size:13px;font-weight:900;color:#6d4c62}input{width:100%;min-height:48px;border:1px solid #f0cddd;border-radius:12px;background:#fffafc;color:#4a2f3e;font-size:16px;padding:10px 12px}input:focus{outline:none;border-color:#e07ba6;box-shadow:0 0 0 4px #fce0ec}button{width:100%;min-height:48px;border:0;border-radius:999px;background:linear-gradient(120deg,#e07ba6,#cf76c4);color:white;font-weight:900;font-size:15px;margin-top:8px;box-shadow:0 10px 24px rgba(208,118,196,.28)}.error{min-height:20px;color:#bd3f72;font-weight:900;font-size:13px;line-height:1.4;margin:10px 0 0;text-align:center}.note{margin-top:14px;text-align:center;color:#a98ba0;font-weight:800;font-size:12px;line-height:1.45}@media(max-width:480px){body{align-items:stretch;padding:12px}.card{display:flex;flex-direction:column;justify-content:center;border-radius:16px}h1{font-size:25px}}' +
    '</style></head><body><form class="card" method="post" action="/login"><div class="mark">M</div><h1>MealMate</h1><p>تسجيل الدخول / Connexion / Login<br>استعملي الحساب وكلمة السر التي وصلتك.</p><label class="field"><span>الحساب / Username</span><input name="username" autocomplete="username" required></label><label class="field"><span>كلمة السر / Password</span><input name="password" type="password" autocomplete="current-password" required></label><button type="submit">دخول / Entrer / Login</button>' + message + '<div class="note">بعد الدخول: افتحي الرابط في Safari ثم Share &gt; Add to Home Screen</div></form></body></html>';
}

function response(body, contentType) {
  return new Response(body, { headers: { 'Content-Type': contentType, 'Cache-Control': 'no-store' } });
}

export default {
  async fetch(request) {
    const url = new URL(request.url);
    if (url.pathname === '/app-icon.svg') return response(ICON_SVG, 'image/svg+xml; charset=utf-8');
    if (url.pathname === '/manifest.webmanifest') return response(MANIFEST, 'application/manifest+json; charset=utf-8');

    if (url.pathname === '/login' && request.method === 'POST') {
      const form = await request.formData();
      const username = String(form.get('username') || '').trim();
      const password = String(form.get('password') || '');
      if (!ACCOUNTS[username] || ACCOUNTS[username].password !== password) {
        return Response.redirect(url.origin + '/login?error=1', 303);
      }
      return new Response(null, {
        status: 303,
        headers: {
          'Location': '/',
          'Set-Cookie': await makeSessionCookie(username)
        }
      });
    }

    if (url.pathname === '/logout') {
      return new Response(null, {
        status: 303,
        headers: {
          'Location': '/login',
          'Set-Cookie': 'mealmate_session=; Path=/; Max-Age=0; HttpOnly; Secure; SameSite=Lax'
        }
      });
    }

    const client = await currentClient(request);
    if (!client) return response(loginPage(url.searchParams.has('error')), 'text/html; charset=utf-8');
    if (url.pathname !== '/' && url.pathname !== '/index.html') return Response.redirect(url.origin + '/', 302);

    const logoutScript = '<script>window.MEALMATE_CLIENT=' + JSON.stringify(client) + ';document.addEventListener("DOMContentLoaded",function(){var c=document.querySelector("header .controls");if(!c)return;var a=document.createElement("a");a.href="/logout";a.textContent=(window.MEALMATE_CLIENT.name||window.MEALMATE_CLIENT.username)+" - Logout";a.style.cssText="border-radius:999px;background:rgba(255,255,255,.9);color:#c75b8c;font-weight:900;padding:8px 12px;text-decoration:none";c.appendChild(a);});</script>';
    return response(APP_HTML.replace('</body>', logoutScript + '</body>'), 'text/html; charset=utf-8');
  }
};
